  "default:semanticPrefixFixDepsChoreOthers": {
    "namespace": "default",
    "description": "Use semantic commit type `fix` for dependencies and `chore` for all others if semantic commits are in use.",
    "body": {
      "packageRules": [
        {
          "matchPackageNames": [
            "*"
          ],
          "semanticCommitType": "chore"
        },
        {
          "matchDepTypes": [
            "dependencies",
            "require"
          ],
          "semanticCommitType": "fix"
        },
        {
          "matchDatasources": [
            "maven"
          ],
          "matchDepTypes": [
            "compile",
            "provided",
            "runtime",
            "system",
            "import",
            "parent"
          ],
          "semanticCommitType": "fix"
        },
        {
          "matchDepTypes": [
            "project.dependencies",
            "project.optional-dependencies"
          ],
          "matchManagers": [
            "pep621",
            "poetry"
          ],
          "semanticCommitType": "fix"
        },
        {
          "matchDepTypes": [
            "dependencies",
            "extras"
          ],
          "matchManagers": [
            "poetry"
          ],
          "semanticCommitType": "fix"
        },
        {
          "matchJsonata": [
            "isLockfileUpdate = true"
          ],
          "semanticCommitType": "chore"
        }
      ]
    }
  },
