  "workarounds:bitnamiDockerImageVersioning": {
    "namespace": "workarounds",
    "description": "Use custom regex versioning for bitnami images",
    "body": {
      "packageRules": [
        {
          "matchCurrentValue": "/^(?<major>\\d+)(?:\\.(?<minor>\\d+)(?:\\.(?<patch>\\d+))?)?-(?<compatibility>.+)-(?<build>\\d+)(?:-r(?<revision>\\d+))?$/",
          "matchDatasources": [
            "docker"
          ],
          "matchPackageNames": [
            "bitnami/**",
            "docker.io/bitnami/**",
            "gcr.io/bitnami-containers/**",
            "*-docker.pkg.dev/vmw-app-catalog/**"
          ],
          "versioning": "regex:^(?<major>\\d+)(?:\\.(?<minor>\\d+)(?:\\.(?<patch>\\d+))?)?(:?-(?<compatibility>.+)-(?<build>\\d+)(?:-r(?<revision>\\d+))?)?$"
        }
      ]
    }
  },
  "workarounds:clamavDockerImageVersioning": {
    "namespace": "workarounds",
    "description": "Use custom regex versioning for ClamAV images",
    "body": {
      "packageRules": [
        {
          "matchDatasources": [
            "docker"
          ],
          "matchPackageNames": [
            "clamav/clamav",
            "clamav/clamav-debian"
          ],
          "versioning": "regex:^(?<major>\\d+)\\.(?<minor>\\d+)(\\.(?<patch>\\d+))?(-(?<build>\\d+))?(_(?<compatibility>.+))?$"
        }
      ]
    }
  },
  "workarounds:containerbase": {
    "namespace": "workarounds",
    "description": "Add some containerbase overrides.",
    "body": {
      "packageRules": [
        {
          "description": "Use node versioning for `(containerbase|renovate)/node` images",
          "matchDatasources": [
            "docker"
          ],
          "matchPackageNames": [
            "/^(?:(?:docker|ghcr)\\.io/)?(?:containerbase|renovate)/node$/"
          ],
          "versioning": "node"
        }
      ]
    }
  },
